import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, useNavigate } from 'react-router-dom';
import './App.css';
import LoginPage from './Components/Login';
import SignupPage from './Components/Signup';
import SideNav from './Components/SideNav';
import ChatBox from './Components/ChatBox';
import HomePage from './Components/HomePage';
import Settings from './Components/Settings';
import logo from './J-Test.png';

function AppContent() {
  const [isAuthenticated, setIsAuthenticated] = useState(
    JSON.parse(localStorage.getItem('isAuthenticated')) || false
  );
  const navigate = useNavigate();

  // Persist the authenticated state
  useEffect(() => {
    localStorage.setItem('isAuthenticated', JSON.stringify(isAuthenticated));
  }, [isAuthenticated]);

  const login = () => {
    setIsAuthenticated(true);
    navigate('/HomePage');
  };

  const logout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem('isAuthenticated'); // Clear state from storage
    navigate('/Login');
  };

  return (
    <div className="App">
      <img src={logo} alt="J-Test Logo" className="logo" />

      {/* Always render SideNav but hide its contents based on isAuthenticated */}
      <SideNav logout={logout} isVisible={isAuthenticated} />

      <Routes>
        <Route path="/Login" element={<LoginPage login={login} />} />
        <Route path="/Signup" element={<SignupPage />} />
        <Route path="/HomePage" element={isAuthenticated ? <HomePage /> : <Navigate to="/Login" />} />
        <Route path="/ChatBox" element={isAuthenticated ? <ChatBox /> : <Navigate to="/Login" />} />
        <Route path="/Settings" element={isAuthenticated ? <Settings /> : <Navigate to="/Login" />} />
        <Route path="/" element={<Navigate to="/Login" />} />
      </Routes>
    </div>
  );
}

function App() {
  return (
    <Router>
      <AppContent />
    </Router>
  );
}

export default App;
